  // But 3^19 is too large (1.16e9), so we need a smarter approach

  // Alternative approach: since the order doesn't matter, we can try all possible subsets for B,
  // and then split the remaining elements into A and C optimally for XOR

  // Iterate all possible non-empty subsets for B
  for (mask <- 1 until (1 << n)) {
    var andB = ~0L
