    for (i <- 0 until n) {
      if ((mask & (1 << i)) != 0) {
        andB &= nums(i)
      } else {
        remaining += nums(i)
      }
    }

    // Now, split remaining into A and C to maximize XOR(A) + XOR(C)
    // The optimal way is to have one element in A and the rest in C, or vice versa, or any split that maximizes the sum
    // Since XOR is associative and commutative, the order doesn't matter, but the grouping does
    // The maximum sum is achieved when one of the partitions has a single element (since XOR of a single element is the element itself)
    // So we can try all possible ways to split remaining into A and C where A is a single element and C is the rest, or vice versa
    val m = remaining.size
    if (m == 0) {
      val current = andB
      if (current > maxSum) maxSum = current
    } else {
      var maxXorSum = 0L
      // Try all possible splits where A is non-empty and C is non-empty
      // But the maximum is achieved when one of them is a single element
      // So try all single element splits
      for (i <- 0 until m) {
