        var xorC = 0L
        for (j <- 0 until m) {
          if (j != i) xorC ^= remaining(j)
        }
        val current = xorA + xorC + andB
        if (current > maxXorSum) maxXorSum = current
      }
      // Also consider the case where A is empty and C is all remaining (or vice versa)
